import{_ as i,o as a,c as e,ag as t}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"🚀 VLTA_AI - 动态架构知识库 (Dynamic Knowledge Base)","description":"","frontmatter":{},"headers":[],"relativePath":"README.md","filePath":"README.md"}'),l={name:"README.md"};function n(o,s,h,r,p,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="🚀-vlta-ai-动态架构知识库-dynamic-knowledge-base" tabindex="-1">🚀 VLTA_AI - 动态架构知识库 (Dynamic Knowledge Base) <a class="header-anchor" href="#🚀-vlta-ai-动态架构知识库-dynamic-knowledge-base" aria-label="Permalink to &quot;🚀 VLTA_AI - 动态架构知识库 (Dynamic Knowledge Base)&quot;">​</a></h1><blockquote><p>这是一个专注探索 AI 生态、Agentic Coding 范式与架构演进的开源数字主脑。基于 VitePress 强劲驱动，为长期深潜前沿科技提供最稳速稳固的知识沉淀基座。</p></blockquote><hr><h2 id="🌎-部署协议与效能管理-vercel-deployment-protocol" tabindex="-1">🌎 部署协议与效能管理 (Vercel Deployment Protocol) <a class="header-anchor" href="#🌎-部署协议与效能管理-vercel-deployment-protocol" aria-label="Permalink to &quot;🌎 部署协议与效能管理 (Vercel Deployment Protocol)&quot;">​</a></h2><p>鉴于“每日记录灵感”的频次极高，为了贯彻真正的极客精神（零浪费、最大化利用 Vercel 服务器时长），本知识库的 CI/CD 流程采取了**特定关键词黑客阻断（Ignored Build Step）**机制。</p><h3 id="⚙️-核心机制-严格按需构建" tabindex="-1">⚙️ 核心机制：严格按需构建 <a class="header-anchor" href="#⚙️-核心机制-严格按需构建" aria-label="Permalink to &quot;⚙️ 核心机制：严格按需构建&quot;">​</a></h3><p>一切日常的冗余 Git Push 都会被线上阻断过滤。<strong>只有当 Commit Message 明确包含 <code>[build]</code> 触发指令时，Vercel 才会真正进入构建状态并向外发布。</strong></p><h3 id="🏁-vercel-后台初始配置指南-配置一次-终身适用" tabindex="-1">🏁 Vercel 后台初始配置指南 (配置一次，终身适用)： <a class="header-anchor" href="#🏁-vercel-后台初始配置指南-配置一次-终身适用" aria-label="Permalink to &quot;🏁 Vercel 后台初始配置指南 (配置一次，终身适用)：&quot;">​</a></h3><ol><li>登录已绑定的 <a href="https://vercel.com" target="_blank" rel="noreferrer">Vercel 控制台</a>，进入本项目的 <strong>Settings -&gt; Git</strong> 选项卡。</li><li>找到 <strong>Ignored Build Step</strong> 面板。</li><li>将下方的拦截 Shell 脚本填入框中并保存：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$VERCEL_GIT_COMMIT_MESSAGE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;\\[build\\]&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> exit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><em>(释义：Vercel 会自动注入环境变量。当提交信息包含 <code>[build]</code> 时，返回退出码 1 允许部署；否则返回 0 自动取消部署。)</em></li></ol><hr><h3 id="👨‍💻-架构师日常心流-daily-workflow" tabindex="-1">👨‍💻 架构师日常心流 (Daily Workflow) <a class="header-anchor" href="#👨‍💻-架构师日常心流-daily-workflow" aria-label="Permalink to &quot;👨‍💻 架构师日常心流 (Daily Workflow)&quot;">​</a></h3><p><strong>场景 1：日常灵感存读（只向 GitHub 归档，拦截构建）</strong> 只管正常走 Git 流，Vercel 监听到推送后会判定退出，不消耗任何免费编译时长：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docs: 记录一下 Manus 分层架构的一个小细节&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span></span></code></pre></div><p><strong>场景 2：版图发布日（强制上线重绘宇宙）</strong> 在觉得积累了一定知识量、或者希望向全球开源社区分发最新的技术内容时，在信息中携带专属指令 <code>[build]</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;release: 新增关于 MCP 模型端点协议的深入研究 [build]&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span></span></code></pre></div><p>伴随这句提交通行证，云端节点被瞬间唤醒，即刻为您重塑最新的知识版图！</p><hr><h2 id="🏗-项目架构规范-project-architecture" tabindex="-1">🏗 项目架构规范 (Project Architecture) <a class="header-anchor" href="#🏗-项目架构规范-project-architecture" aria-label="Permalink to &quot;🏗 项目架构规范 (Project Architecture)&quot;">​</a></h2><p>为了保持知识库的长期可维护性，本项目采用分类目录管理方案：</p><ul><li><strong><code>knowledge/</code></strong>: 存放 AI 技术干货、论文解析、工具评测。</li><li><strong><code>docs/</code></strong>: 存放项目自身的架构定义（PRD, SPEC）。</li><li><strong><code>index.md</code></strong>: 站点门户。</li></ul><h3 id="✍️-知识入库流程" tabindex="-1">✍️ 知识入库流程 <a class="header-anchor" href="#✍️-知识入库流程" aria-label="Permalink to &quot;✍️ 知识入库流程&quot;">​</a></h3><ol><li><strong>新建文档</strong>：根据类别放入 <code>knowledge/</code> 或 <code>docs/</code>。</li><li><strong>注册导航</strong>：在 <code>.vitepress/config.mts</code> 的 <code>sidebar</code> 中添加新链接。</li><li><strong>推送到云端</strong>：使用 <code>[build]</code> 关键词触发 Vercel 构建。</li></ol><p>没有任何发版压力，也没有任何失败提醒。专注知识，即是架构！</p>`,23)])])}const g=i(l,[["render",n]]);export{k as __pageData,g as default};
